block_descriptions.code:
always @ (posedge Clock)
begin
	a<=~Coin_1;
	b<=a;
	c<=a&&(~b);
end

always @ (posedge Clock)
begin
	d<=~Coin_5;
	e<=d;
	f<=d&&(~e);
end

always @ (posedge Clock)
begin
	gg<=~Coin_return;
	hh<=gg;
	ii<=gg&&(~hh);
end

always @ (posedge Clock , negedge Reset_n)
begin
	if(!Reset_n)
		present_state <= Init;
	else
		present_state <= next_state;
end

//Control unit state

always @ (*)
begin
	case(present_state)
		Init:
			begin 
				next_state = Wait;
				sel_en  = 1'b0;		//0	选择器使能关
				sel_sel = 1'b0;		//0	投币1元
				Cnt_clr = 1'b0;		//0	计数器清零
				Cnt_en  = 1'b0;		//0	计数器使能关
				Cnt_ld  = 1'b0;		//0	不加载预值
				Cnt_ud  = 1'b0;		//0	下行计数关
				Place_cup  = 1'b0;
				Inject_cof = 1'b0;
				Refund = 1'b0;
			end
		Wait:
			begin
		  	row_1 <="Please invest 1 ";    //第一行显示的16*1字节个内容
         row_2 <="RMB or 5 RMB ^.^";    //第二行显示的16*1字节个内容
				if(c)
					begin 
						next_state = Add_1;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else if(f)
					begin
						next_state = Add_5;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else
					begin
						next_state = Wait;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
			end
		Add_1:
			begin 
				next_state = Comp;
				sel_en = 1'b1;		//1	选择器使能开
				sel_sel= 1'b0;		//0	投币1元
				Cnt_clr= 1'b1;		//1	计数器不清零
				Cnt_en = 1'b1;		//1	计数器使能开
				Cnt_ld = 1'b1;		//1	加载预值
				Cnt_ud = 1'b0;		//0	下行计数关
				Place_cup = 1'b0;
				Inject_cof= 1'b0;
				Refund = 1'b0;
			end	
		Add_5:
			begin 
				next_state = return_1;
				sel_en = 1'b1;		//1	选择器使能开
				sel_sel= 1'b1;		//1	投币5元
				Cnt_clr= 1'b1;		//1	计数器不清零
				Cnt_en = 1'b1;		//1	计数器使能开
				Cnt_ld = 1'b1;		//1	加载预值
				Cnt_ud = 1'b0;		//0	下行计数关
				Place_cup = 1'b0;
				Inject_cof= 1'b0;
				Refund = 1'b0;
			end
		return_1:
			begin
					  	row_1 <="Please wait for ";    //第一行显示的16*1字节个内容
                  row_2 <="coin refund! ^_^";    //第二行显示的16*1字节个内容
				Refund = 1'b1;		//退款信号
				if(ii)
					begin
						next_state = Comp;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b1;		//1	投币5元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b1;		//1	计数器使能开
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b1;		//1	下行计数开
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
					end
	   		else 
					begin
					next_state = return_1;
					sel_en = 1'b0;		//0	选择器使能关
					sel_sel= 1'b0;		//0	投币1元
					Cnt_clr= 1'b1;		//1	计数器不清零
					Cnt_en = 1'b0;		//0	计数器使能关
					Cnt_ld = 1'b0;		//0	不加载预值
					Cnt_ud = 1'b0;		//0	下行计数关
					Place_cup = 1'b0;
					Inject_cof= 1'b0;
					Refund = 1'b1;
					end

			end

		Comp:
			begin
				if(Less_3)
					begin
						next_state = Wait;
						sel_en  = 1'b0;		//0	选择器使能关
						sel_sel = 1'b0;		//0	投币1元
						Cnt_clr = 1'b1;		//1	计数器不清零
						Cnt_en  = 1'b0;		//0	计数器使能关
						Cnt_ld  = 1'b1;		//1	加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else if(Eql_3)
					begin
						next_state = Place;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b1;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else if(Grt_3)
					begin
						next_state = return_1;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else
					begin
						next_state = Comp;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
			end	
		Place:
			begin 
			Place_cup = 1'b1;
				if(Cup_rdy)
					begin
						next_state = Release;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b1;
						Refund = 1'b0;
					end
				else 
					next_state = Place;	
			end	 
		Release:
			begin 
					row_1 <="The cup is alre-";    //第一行显示的16*1字节个内容
               row_2 <="ady in place !  "; 
				Inject_cof= 1'b1;
				if(Cof_rdy)
					begin
						next_state = Init;
						sel_en = 1'b0;		//0	选择器使能关
						sel_sel= 1'b0;		//0	投币1元
						Cnt_clr= 1'b1;		//1	计数器不清零
						Cnt_en = 1'b0;		//0	计数器使能关
						Cnt_ld = 1'b0;		//0	不加载预值
						Cnt_ud = 1'b0;		//0	下行计数关
						Place_cup = 1'b0;
						Inject_cof= 1'b0;
						Refund = 1'b0;
					end
				else 
					next_state = Release;			
			end
		default:
			begin 
			   present_state = Init;
				next_state = Init;
				sel_en = 1'b0;		//0	选择器使能关
				sel_sel= 1'b0;		//0	投币1元
				Cnt_clr= 1'b0;		//0	计数器清零
				Cnt_en = 1'b1;		//1	计数器使能开
				Cnt_ld = 1'b0;		//0	不加载预值
				Cnt_ud = 1'b0;		//0	下行计数关
				Place_cup = 1'b0;
				Inject_cof= 1'b0;
				Refund = 1'b0;
			end
	endcase					
end
endmodule
